import { AsyncStorage } from 'react-native';
import { AESCrypto } from 'react-native-aes-crypto';
import { CryptoJS } from 'crypto-js';

// Import encryption key from config file
const ENCRYPTION_KEY = require('./config').ENCRYPTION_KEY;

// Encrypt user profiles, payment information, and auth tokens using AES-256
export const encrypt = (data) => {
  return AESCrypto.encrypt(data, ENCRYPTION_KEY);
};

// Decrypt user profiles, payment information, and auth tokens using AES-256
export const decrypt = (data) => {
  return AESCrypto.decrypt(data, ENCRYPTION_KEY);
};

// Encrypt data using CryptoJS
export const encryptWithCryptoJS = (data) => {
  return CryptoJS.AES.encrypt(data, ENCRYPTION_KEY).toString();
};

// Decrypt data using CryptoJS
export const decryptWithCryptoJS = (data) => {
  return CryptoJS.AES.decrypt(data, ENCRYPTION_KEY).toString(CryptoJS.enc.Utf8);
};